mapper.select:
select overwork.*,employee.name as emname from `overwork` left join `employee` on overwork.userid = employee.id
and title like concat('%',#{title},'%') and userid =#{userid}
order by id desc

mapper.insert:
INSERT INTO overwork(
    userid, title, text, status, reason,
    starttime, endtime, time,emname
) VALUES (
             #{userid}, #{title}, #{text}, #{status}, #{reason},
             #{starttime}, #{endtime}, #{time},#{emname}
         )

mapper.update:
UPDATE overwork
text = #{text}, status = #{status}, reason = #{reason},
WHERE id = #{id}
